import React from 'react';

import { HistoryConsumer } from '../../../context/HistoryContext';
import classNames from 'classNames';

export const UnwindButton = React.memo((props) => {
	return (
		<HistoryConsumer>
			{(history) => {
				return (
					<button
						className={classNames('fas', 'fa-chevron-left', 'com-a-UnwindSegue')}
						onClick={history.goBack}
					/>
				);
			}}
		</HistoryConsumer>
	);
});
