import React from 'react';

import { CalendarManager } from './CalendarManger';

class DayCell extends React.Component {
	render() {
		const { date, isMonthInner, active } = this.props;
		if (isMonthInner) {
			return (
				<td className={`is-active ${active ? 'item-in' : ''}`} onClick={() => this.props.onCellClick()}>
					{date}
				</td>
			);
		} else {
			return <td className="is-disabled">{date}</td>;
		}
	}
}

function generateCalendarDates(mcal) {
	function dayCount2day(w, d, dayCount) {
		const FIRST_DAY = mcal.getFirstDay();
		const LAST_MONTH_LAST_DATE = mcal.getLastMonthLastDate();
		const LAST_DATE = mcal.getLastDate();
		if (w == 0 && d < FIRST_DAY) {
			return `${mcal.getMonth() - 1}-${LAST_MONTH_LAST_DATE - FIRST_DAY + d + 1}`;
		} else if (dayCount > LAST_DATE) {
			return `${mcal.getMonth() + 1}-${dayCount - LAST_DATE}`;
		} else {
			return `${mcal.getMonth()}-${dayCount}`;
		}
	}

	let dayCount = 1;
	const FIRST_DAY = mcal.getFirstDay();
	const ret = [];
	for (let w = 0; w < 6; w++) {
		for (let d = 0; d < 7; d++) {
			const monthDate = dayCount2day(w, d, dayCount);
			ret.push(monthDate);
			if (w != 0 || d >= FIRST_DAY) {
				dayCount++;
			}
		}
	}
	return ret;
}

export class Calendar extends React.Component {
	constructor(props) {
		super(props);
		const calManager = new CalendarManager(new Date());
		this.state = {
			calManager,
			calDates: generateCalendarDates(calManager)
		};
		this.moveMonth = this.moveMonth.bind(this);
	}
	moveMonth(forward) {
		const calManager = this.state.calManager;
		calManager.moveMonth(forward);
		this.setState({
			calManager,
			calDates: generateCalendarDates(calManager)
		});
	}
	render() {
		const MCAL_LIST = this.state.calDates;
		const CAL_MONTH = MCAL_LIST[Math.round(MCAL_LIST.length / 2)].split('-')[0];

		const calendarHeaderHTML = [ '日', '月', '火', '水', '木', '金', '土' ].map((week) => {
			return <td key={week}>{week}</td>;
		});

		let monthCal = [];
		for (let w = 0; w < 6; w++) {
			let week = [];
			for (let d = 0; d < 7; d++) {
				const mcalIndex = w * 7 + d;
				const [ month, date ] = MCAL_LIST[mcalIndex].split('-');
				week.push(<DayCell key={mcalIndex} date={date} isMonthInner={CAL_MONTH === month} />);
			}
			monthCal.push(<tr key={w}>{week}</tr>);
		}

		return (
			<section>
				<div className="com-a-Calendar">
					<div className="com-a-Calendar__navi-area">
						<button
							type="button"
							className="com-a-Calendar__button-back"
							onClick={() => this.moveMonth(false)}
						>
							前の月
						</button>
						<h1 className="month-calendar__title">{`${CAL_MONTH}月`}</h1>
						<button
							type="button"
							className="com-a-Calendar__button-next"
							onClick={() => this.moveMonth(true)}
						>
							次の月
						</button>
					</div>
					<table className="month-calendar">
						<tbody>
							<tr>{calendarHeaderHTML}</tr>
							{monthCal}
						</tbody>
					</table>
				</div>
			</section>
		);
	}
}
