export class CalendarManager {
  constructor(date) {
    (this.year = date.getFullYear()), (this.month = date.getMonth() + 1);
  }
  moveMonth(isForward) {
    let year = this.year;
    let month = this.month;
    if (isForward) {
      month++;
      if (month > 12) {
        year++;
        month = 1;
      }
    } else {
      month--;
      if (month < 1) {
        year--;
        month = 12;
      }
    }
    this.year = year;
    this.month = month;
  }
  goMonth() {
    moveMonth(true);
  }
  backMonth() {
    moveMonth(false);
  }
  getMonth() {
    return this.month;
  }
  getFirstDateObj() {
    return new Date(this.year, this.month - 1, 1);
  }
  getFirstDay() {
    const d = new Date(this.year, this.month - 1, 1);
    return d.getDay();
  }
  getFirstDate() {
    const d = new Date(this.year, this.month - 1, 1);
    return d.getDate();
  }
  getLastDateObj() {
    return new Date(this.year, this.month, 0);
  }
  getLastDate() {
    const d = new Date(this.year, this.month, 0);
    return d.getDate();
  }
  getLastDay() {
    const d = new Date(this.year, this.month, 0);
    return d.getDay();
  }
  getLastMonthLastDateObj() {
    return new Date(this.year, this.month - 2, 0);
  }
  getLastMonthLastDate() {
    const d = new Date(this.year, this.month - 2, 0);
    return d.getDate();
  }
  getLastMonthLastDay() {
    const d = new Date(this.year, this.month - 2, 0);
    return d.getDay();
  }
}
