import React, { useState } from 'react';
import { Link } from 'react-router-dom';

import { ProfileButton } from './atoms/Button';
import { NaviBar } from './atoms/NaviBar';
import { BookInfoCard } from './molecues/BookInfoCard/BookInfoCard';
import { Search } from './workspaces/Search';

export const HomeView = (props) => {
	const [ isSearchOpen, setSearchOpen ] = useState(false);

	const dummyBooks = [
		{
			src: '/sq_monkey.jpeg',
			title: 'Vim',
			id: 'ean'
		},
		{
			src: '/rhino.jpeg',
			title: 'JavaScript',
			id: 'en'
		},
		{
			src: '/regex.jpeg',
			title: 'Regular Expression',
			id: 'an'
		}
	];

	return (
		<React.Fragment>
			<NaviBar>
				{!isSearchOpen ? <ProfileButton href="/notif" /> : null}
				<Search setSearchOpen={setSearchOpen} isSearchOpen={isSearchOpen} />
			</NaviBar>
			<div className="HomeView__book-info-card">
				{dummyBooks.map((x) => {
					return (
						<Link key={x.id} to={`/book/${x.id}`}>
							<BookInfoCard src={x.src} title={x.title}>
								<p>Some Details</p>
							</BookInfoCard>
						</Link>
					);
				})}
			</div>
		</React.Fragment>
	);
};
