import React from "react";
import { Link } from "react-router-dom";

export const PrimaryButton = React.memo(props => {
  if (props.href) {
    // TODO: option-t
    return (
      <Link to={props.href} className="com-a-PrimaryButton">
        {props.children}
      </Link>
    );
  }
  return (
    <button className="com-a-PrimaryButton" onClick={props.onClick}>
      {props.children}
    </button>
  );
});
