import React, { useState } from 'react';

import { UnwindButton, PrimaryButton, SecondaryButton } from './atoms/Button';

import { Calendar } from './atoms/Calendar';
import { NaviBar } from './atoms/NaviBar';
import { BookDetail } from './molecues/BookDetail/BookDetail';
import { SingleButtonSprashView } from './organisms/SingleButtonSprashView';

export const BookView = (props) => {
	const [ isRentalSprashOpen, setRentalSprashOpen ] = useState(false);
	const [ isReservationSprashOpen, setReservationSprashOpen ] = useState(false);
	function justNowRental() {
		setRentalSprashOpen(true);
	}
	function segueReservation() {
		setReservationSprashOpen(true);
	}
	function segueLaterRental() {}
	return (
		<React.Fragment>
			<div>
				<NaviBar>
					<UnwindButton />
					<h1 className="BookView__title">{'本のタイトル'}</h1>
				</NaviBar>
				<BookDetail sideByTitle={`在庫: ${0}冊`} title="オライリーの何か" src={'/sq_monkey.jpeg'}>
					<span className="BookView__now-rent-button">
						<PrimaryButton onClick={justNowRental}>今すぐ借りる</PrimaryButton>
					</span>
					<span className="BookView__show-reserve-button">
						<PrimaryButton onClick={segueReservation}>予約を見る</PrimaryButton>
					</span>
					<SecondaryButton onClick={segueLaterRental}>または開始日を別日にする</SecondaryButton>
				</BookDetail>
			</div>
			{isRentalSprashOpen ? (
				<SingleButtonSprashView href="/home" buttonText="完了">
					<p className="BookView__sprash-text">レンタルが完了しました！</p>
				</SingleButtonSprashView>
			) : null}
			{isReservationSprashOpen ? (
				<SingleButtonSprashView onClick={() => setReservationSprashOpen(false)} buttonText="戻る">
					<div className="BookView__sprash-calendar">
						<Calendar disableDates={[ new Date() ]} />
					</div>
				</SingleButtonSprashView>
			) : null}
		</React.Fragment>
	);
};
