import React, { useState } from 'react';

import { SearchArea } from './SearchArea';
import { SearchButton } from './SearchButton';

export const Search = (props) => {
	const [ searchText, setSearchText ] = useState('');
	console.log(searchText);
	return (
		<React.Fragment>
			{props.isSearchOpen ? (
				<SearchArea searchText={searchText} onChange={setSearchText} close={() => props.setSearchOpen(false)} />
			) : (
				<span className="w-Search__search-button">
					<SearchButton onClick={() => props.setSearchOpen(true)} />
				</span>
			)}
		</React.Fragment>
	);
};
