import React from 'react';
import classNames from 'classnames';

export const SearchArea = (props) => {
	function inputText(e) {
		props.onChange(e.target.value);
	}
	return (
		<React.Fragment>
			<input
				className="w-Search-SearchArea"
				type="search"
				placeholder="検索"
				onChange={(e) => inputText(e)}
				value={props.searchText}
			/>
			<button className={classNames('w-Search-SeachArea__cancel', 'fas fa-times')} onClick={props.close} />
		</React.Fragment>
	);
};
