import React from 'react';
import { render } from 'react-dom';
import { Provider } from 'react-redux';
import { Route, Switch } from 'react-router';
import { ConnectedRouter } from 'connected-react-router';

import { createStore, history } from './createStore';
import { LoginContainer } from './container/LoginContainer';
import { HomeContainer } from './container/HomeContainer';
import { BooksContainer } from './container/BooksContainer';
import { BookContainer } from './container/BookContainer';
import { NotifContainer } from './container/NotifContainer';
import { HistoryProvider } from './components/context/HistoryContext';

const store = createStore();

render(
	<Provider store={store}>
		<ConnectedRouter history={history}>
			<HistoryProvider value={history}>
				<Switch>
					<Route exact path="/" render={() => <LoginContainer />} />
					<Route exact path="/home" render={() => <HomeContainer />} />
					<Route exact path="/book" render={() => <BooksContainer />} />
					<Route path="/book/:id" render={() => <BookContainer />} />
					<Route path="/notif" render={() => <NotifContainer />} />
					<Route render={() => <div>Good night</div>} />
				</Switch>
			</HistoryProvider>
		</ConnectedRouter>
	</Provider>,
	document.getElementById('content')
);
