import React from 'react';
import { Link } from 'react-router-dom';

export const ProfileButton = (props) => {
	// FIXME: option-t
	if (props.href) {
		return (
			<Link className="com-a-Button-Profile" to={props.href}>
				<img className="com-a-Button-Profile__img" src="/taffy.png" />
			</Link>
		);
	}
	return <button className="com-a-Button-Profile">Profile</button>;
};
